\begin{lemma}\label{lf1}
    Let $x \in K_n$, $m \in \{0, 1, 2, \dots, n\}$, and $r \in \{0, 1, \dots, n - m\}$.
    If $\overline{\partial}_{[m]}(x) = e_{[n] \setminus [m]}$, then 
    \begin{equation*}
        \overline{\partial}_{[m+r]}(x) = e_{[n] \setminus [m+r]}.
    \end{equation*}
\end{lemma}

