\begin{definition}
    The \emph{level function} $\mathcal{L} : K_n \to \{0, 1, \dots, n\}$ is defined by
    \[
    \mathcal{L}(x) = \min \{i \in \{0, 1, \dots, n\} \mid \overline{\partial}_{[i]}(x) = e_{[n] \setminus [i]} \}.
    \]
\end{definition}

