\begin{theorem}\label{RL_formula}
    Let $x \in K_n$ and $i \in [n]$.
    Then 
    \begin{equation}\label{formula}
        \mathcal{L}(x a_i) = 
        \begin{cases}
            \mathcal{L}(x) - 1, & i = \mathcal{L}(x), \\
            \mathcal{L}(x), &  i \neq \mathcal{L}(x).
        \end{cases}
    \end{equation}
\end{theorem}

