\begin{definition}\label{g_definition}
    We define the function $g : \{0, 1,\dots, n\} \times [n] \to \{0, 1, \dots, n\}$ by
    \[
    g(i, j) =
    \begin{cases}
        i - 1, & i = j, \\
        i, & i \neq j.  
    \end{cases}
    \]
\end{definition}

